var months = [
  { name: 'JANUARY',   days: 31 },
  { name: 'FEBRUARY',  days: 28 },
  { name: 'MARCH',     days: 31 },
  { name: 'APRIL',     days: 30 },
  { name: 'MAY',       days: 31 },
  { name: 'JUNE',      days: 30 },
  { name: 'JULY',      days: 31 },
  { name: 'AUGUST',    days: 31 },
  { name: 'SEPTEMBER', days: 30 },
  { name: 'OCTOBER',   days: 31 },
  { name: 'NOVEMBER',  days: 30 },
  { name: 'DECEMBER',  days: 31 }
];

var year = 2026;
if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) {
  months[1].days = 29;
}

var items = [];

for (var i = 0; i < months.length; i++) {
  var tbl = 'TBL_' + months[i].name;
  items.push({ json: { sql: 'CREATE TABLE IF NOT EXISTS ' + tbl + ' (date_ts TIMESTAMP)', phase: 'create', table: tbl } });
  items.push({ json: { sql: 'TRUNCATE TABLE ' + tbl, phase: 'truncate', table: tbl } });
}

for (var i = 0; i < months.length; i++) {
  var tbl = 'TBL_' + months[i].name;
  var monthNum = i + 1;
  var mm = monthNum < 10 ? '0' + monthNum : '' + monthNum;
  for (var d = 1; d <= months[i].days; d++) {
    var dd = d < 10 ? '0' + d : '' + d;
    var ts = year + '-' + mm + '-' + dd + ' 00:00:00';
    items.push({ json: { sql: "INSERT INTO " + tbl + " (date_ts) VALUES (TIMESTAMP '" + ts + "')", phase: 'insert', table: tbl, date: ts } });
  }
}

return items;
